sys_script_client.script:
/**
 * GEM/Duypd - 18.05.2026:
 * TAM/Sprint 3/Story TAM_52
 * 
 * Trigger when candidate field value changes.
 * Fetch candidate information from table x_1763182_talent_0_candidate
 * by using GlideAjax TAMUtils.getTableInfomation().
 * 
 * Returned fields:
 * - u_email
 * - u_username
 * - u_phone_number
 * 
 * Auto populate related fields on the form:
 * - u_client
 * - u_candidate_username
 * - u_candidate_email
 * - candidate_phone_number
 */
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue === '') {
        return;
    }

    var fieldFetching = "u_email,u_username,u_phone_number";

    var gaCandidate = new GlideAjax("TAMUtils");
    gaCandidate.addParam("sysparm_name", "getTableInfomation");
    gaCandidate.addParam("sysparm_table_name", "x_1763182_talent_0_candidate");
    gaCandidate.addParam("sysparm_record_id", newValue);
    gaCandidate.addParam("sysparm_field_return", fieldFetching);

    gaCandidate.getXMLAnswer(function(res) {
        var result = JSON.parse(res);
        g_form.setValue('u_client', result.u_username);
        g_form.setValue('u_candidate_username', result.u_username);
        g_form.setValue('u_candidate_email', result.u_email);
        g_form.setValue('candidate_phone_number', result.u_phone_number);
    });
}
